// 將 EasyStore products 對應到 Creator Service_Catalog 格式
const response = $json;
const products = response.products || response || [];
const mapped = [];

for (const product of (Array.isArray(products) ? products : [])) {
  // 取第一個 variant 的價格
  const variants = product.variants || [];
  const price = variants.length > 0 ? parseFloat(variants[0].price) || 0 : 0;

  // 取第一張圖片
  const images = product.images || [];
  const image_url = images.length > 0 ? (images[0].src || '') : '';

  mapped.push({
    Source: 'EasyStore',
    External_ID: product.handle || String(product.id),
    Name: product.title || '',
    Raw_Description: product.body_html || '',
    Price: price,
    Image_URL: image_url,
    Active: product.published !== false,
    Product_URL: product.url || `https://__ES_SHOP__/products/${product.handle}`
  });
}

return [{ json: { product_list: mapped, count: mapped.length } }];
